import React from 'react';

const foodItems = [
  { id: 'biryani', label: 'Biryani', icon: '🍚' },
  { id: 'haleem', label: 'Haleem', icon: '🍲' },
  { id: 'chaat', label: 'Fruit Chaat', icon: '🥗' },
  { id: 'sharbat', label: 'Sharbat', icon: '🧃' },
  { id: 'dessert', label: 'Dessert', icon: '🍰' }
];

export default function FoodSelection({ selectedItems = [], onChange }) {
  const handleItemClick = (itemId) => {
    const isSelected = selectedItems.includes(itemId);
    const newSelection = isSelected
      ? selectedItems.filter(id => id !== itemId)
      : [...selectedItems, itemId];
    onChange?.(newSelection);
  };

  return (
    <div className="food-selection">
      <style jsx>{`
        .food-selection {
          width: 100%;
          margin: 40px 0;
        }

        .food-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
          gap: 16px;
          margin-top: 20px;
        }

        .food-item {
          position: relative;
          padding: 20px 16px;
          background: rgba(255, 255, 255, 0.03);
          border: 2px solid rgba(212, 175, 55, 0.3);
          border-radius: 12px;
          cursor: pointer;
          transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 8px;
          text-align: center;
        }

        .food-item:hover {
          background: rgba(212, 175, 55, 0.1);
          border-color: rgba(212, 175, 55, 0.6);
          transform: translateY(-4px);
          box-shadow: 0 8px 24px rgba(212, 175, 55, 0.15);
        }

        .food-item.selected {
          background: linear-gradient(135deg, rgba(212, 175, 55, 0.2), rgba(255, 215, 0, 0.1));
          border-color: #d4af37;
          box-shadow: 0 0 20px rgba(212, 175, 55, 0.3), inset 0 0 20px rgba(212, 175, 55, 0.05);
        }

        .food-item.selected::before {
          content: '';
          position: absolute;
          top: -8px;
          right: -8px;
          width: 24px;
          height: 24px;
          background: #d4af37;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 14px;
          color: #1a1f3a;
          font-weight: bold;
          box-shadow: 0 0 12px rgba(212, 175, 55, 0.6);
        }

        .food-item.selected::after {
          content: '✓';
          position: absolute;
          top: -5px;
          right: -5px;
          color: #1a1f3a;
          font-weight: bold;
          font-size: 12px;
        }

        .food-icon {
          font-size: 36px;
          line-height: 1;
          filter: drop-shadow(0 2px 4px rgba(212, 175, 55, 0.2));
        }

        .food-label {
          color: #f6e7c1;
          font-size: 14px;
          font-weight: 600;
          font-family: 'Montserrat', sans-serif;
          letter-spacing: 0.3px;
          transition: color 0.3s ease;
        }

        .food-item.selected .food-label {
          color: #ffd700;
        }

        .food-selection-header {
          color: #d4af37;
          font-size: 18px;
          font-weight: 600;
          font-family: 'Montserrat', sans-serif;
          letter-spacing: 1px;
          text-transform: uppercase;
          margin-bottom: 12px;
        }

        .food-selection-hint {
          color: rgba(212, 175, 55, 0.7);
          font-size: 14px;
          font-family: 'Montserrat', sans-serif;
          font-style: italic;
        }

        @media (max-width: 768px) {
          .food-grid {
            grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
            gap: 12px;
          }

          .food-item {
            padding: 16px 12px;
          }

          .food-icon {
            font-size: 28px;
          }

          .food-label {
            font-size: 12px;
          }
        }
      `}</style>

      <div className="food-selection-hint">Choose items you'd like to enjoy</div>

      <div className="food-grid">
        {foodItems.map(item => (
          <div
            key={item.id}
            className={`food-item ${selectedItems.includes(item.id) ? 'selected' : ''}`}
            onClick={() => handleItemClick(item.id)}
            role="button"
            tabIndex={0}
            aria-label={`${item.label} - ${selectedItems.includes(item.id) ? 'selected' : 'not selected'}`}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                handleItemClick(item.id);
              }
            }}
          >
            <div className="food-icon">{item.icon}</div>
            <div className="food-label">{item.label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
